function nullish(x) {
    return (x == null) || (x === CLEAR_SENTINEL) || (x.toString().trim() === '')
}

function normalizeSide(s, ri, engine, defaultSide="Mid") {
    if (!s) return defaultSide;
    let k = String(s).trim().toUpperCase();
    if ((k === 'AUTO') && (ri != null) && (engine)) {
        k = engine.getCell(ri, 'userSide');
    }
    return SIDE_ALIASES?.[k] ?? (null)
}

function getAllMarketColumns() {
    const markets = WF_FULL;
    const sides = SIDES;
    const qts = QUOTE_TYPES;
    const cols = [];

    for (const market of markets) {
        for (const side of sides) {
            for (const qt of qts) {
                cols.push(StringFormatter.clean_camel(`${market}_${side}_${qt}`));
            }
        }
    }
    return cols;
}

function _generateBenchmarkColumns() {
    const markets = WF_FULL;
    return WF_FULL.map(mkt => {
        return StringFormatter.clean_camel(`${mkt}_BenchmarkIsin`)
    })
}

function generateBenchmarkTenorColumns() {
    return _generateBenchmarkColumns().map(t => {
        const new_name = t.replace('Isin', 'Tenor');
        const header_name = StringFormatter.toUppercaseFirstWord(new_name.replace("Benchmark", " Bench "));
        return {
            field: new_name,
            headerName: header_name,
            width: 40,
            context: {
                dataType: 'select',
                customColumnGroup: 'Bond/Pricing',
                availableInApi:true,
                allowGrouping:false,
                isSearchable:false,
                aggregationName: header_name,
                showInfo: true,
                suppressColumnMenu: [],
                "metaTags": ["benchmark", "bm", "tenor", "maturity", 'bench'],
                deps: [t],
                settingKeys: ['UST_MAP'],
                compute: (ri, engine, settings) => {
                    const m = settings?.UST_MAP;
                    if (!m) return;
                    if (!engine.fieldSet().has(t)) return null;
                    const bench = engine.getCell(ri, t);
                    return m.has(bench) ? m.get(bench) : null;
                }
            }
        }
    })
}

function readCell(engine, ri, col) {
    try { return engine.getCell(ri, col); } catch (_) { return undefined; }
}

function pctOfSize(px, size) { return (px / 100) * size; }
function pxFromProceeds(proceeds, size) { return (proceeds / size) * 100; }
function bpsFromPx(px, ref) { return (px / ref - 1) * 10_000; }
function pxFromBps(ref, bps) { return ((bps / 10_000) + 1) * ref; }

export function getQuoteType(v) {
    const key = String(v ?? '').toLowerCase();
    return QT_MAP[key] ?? String(v).toUpperCase();
}

function _extractId(params) {
    const data = params?.data ?? params;
    if (!data || typeof data !== 'object') return null;
    let id = data?.['__srcIndex'] ?? data?.['__pid'];
    if (id == null) id = Object.keys(data).filter(x=>x.startsWith('__'));
    return id != null ? id : null;
}

function _isBpsQt(qt) {
    return BPS_QT.has(qt);
}

// bad is good
function isFlipped(side, qt) {
    if (side === 'BUY' && _isBpsQt(qt)) return true
    return side === 'SELL' && !_isBpsQt(qt);
}

const BUCKET_EPS = 1e-6;
function firmBucketSortKey(v) {
    if (v == null) return null;
    const raw = String(v).trim();
    if (!raw) return null;
    const s = raw.toLowerCase().replace(/\s+/g, '');
    if (s === 'flat') return 0;
    const m = s.match(/^([<>])(-?\d+(?:\.\d+)?)(mio|million|mn|mm|m)?$/);
    if (!m) return NaN;
    const op = m[1];
    const num = Number(m[2]);
    const unit = m[3];

    const factor =
        unit === 'mio' || unit === 'million' || unit === 'mn' || unit === 'mm' || unit === 'm'
            ? 1_000_000
            : 1;

    const base = num * factor;

    // make "<0" slightly less than 0, ">0" slightly greater than 0
    return base + (op === '<' ? -BUCKET_EPS : BUCKET_EPS);
}

function firmBucketComparator(valueA, valueB) {
    const keyA = firmBucketSortKey(valueA);
    const keyB = firmBucketSortKey(valueB);

    const aNull = keyA == null;
    const bNull = keyB == null;
    if (aNull && bNull) return 0;
    if (aNull) return 1;
    if (bNull) return -1;

    const aBad = Number.isNaN(keyA);
    const bBad = Number.isNaN(keyB);
    if (aBad && bBad) return String(valueA).localeCompare(String(valueB));
    if (aBad) return 1;
    if (bBad) return -1;

    return keyA - keyB;
}

const firmBucketSetFilterComparator = (a, b) => firmBucketComparator(a, b);

export function getRefLevelRaw(ri, mkt, side, qt, engine, { waterfall = true } = {}) {
    const qtl = String(qt ?? '').toLowerCase();
    if (qtl === 'cash') return _getRefLevelCash(ri, side, mkt, engine, waterfall);
    if (qtl === 'dirty' || qtl === 'dirty_cash') return _getRefLevelDirty(ri, side, mkt, engine, waterfall);
    if (qtl === 'bps') return _getRefLevelBpsBid(ri, side, mkt, engine, waterfall);
    if (qtl === 'bps mid' || qtl === 'bpsmid') return _getRefLevelBpsMid(ri, side, mkt, engine, waterfall);

    const col = StringFormatter.clean_camel(String(mkt) + '_' + side + '_' + qt);
    const v = readCell(engine, ri, col);
    if (v != null) return { mkt, value: v, col };

    if (mkt === 'Dynamic' || waterfall !== false) {
        const water = _getWaterfallLevel(ri, engine, side, qt, mkt);
        if (water && water.length === 3) return { mkt: water[0], value: water[1], col: water[2] };
    }
    return null;
}

export function getRefLevelCol(ri, mkt, side, qt, engine, {waterfall=true}={}) {
    const raw = getRefLevelRaw(ri, mkt, side, qt, engine, {waterfall: waterfall});
    return raw?.col
}

export function getRefLevelValue(ri, mkt, side, qt, engine, {waterfall=true}={}) {
    const raw = getRefLevelRaw(ri, mkt, side, qt, engine, {waterfall: waterfall});
    return raw?.value
}

function _getRefLevelCash(ri, side, mkt, engine, waterfall = true) {
    const d = getRefLevelRaw(ri, mkt, side, 'PX', engine, { waterfall });
    if (!d || d.value == null) return null;
    const size = coerceToNumber(engine.getCell(ri, 'grossSize'), { onNaN: null });
    if (size == null) return null;
    return { mkt: d.mkt, value: (d.value / 100) * size, col: d.col };
}

function _getRefLevelDirty(ri, side, mkt, engine, waterfall = true) {
    const d = getRefLevelRaw(ri, mkt, side, 'PX', engine, { waterfall });
    if (!d || d.value == null) return null;
    const size = coerceToNumber(engine.getCell(ri, 'grossSize'), { onNaN: null });
    const accrued = coerceToNumber(engine.getCell(ri, 'accruedInterest'), { onNaN: 0 });
    if (size == null) return null;
    return { mkt: d.mkt, value: (d.value / 100) * size + accrued, col: d.col };
}

function _getRefLevelBpsBid(ri, side, mkt, engine, waterfall = true) {
    const d = getRefLevelRaw(ri, mkt, side, 'PX', engine, { waterfall });
    const dbid = getRefLevelRaw(ri, mkt, 'Bid', 'PX', engine, { waterfall });
    if (!d || !dbid || d.value == null || dbid.value == null || dbid.value === 0) return null;
    return { mkt: d.mkt, value: bpsFromPx(d.value, dbid.value), col: d.col };
}

function _getRefLevelBpsMid(ri, side, mkt, engine, waterfall = true) {
    const d = getRefLevelRaw(ri, mkt, side, 'PX', engine, { waterfall });
    const dmid = getRefLevelRaw(ri, mkt, 'Mid', 'PX', engine, { waterfall });
    if (!d || !dmid || d.value == null || dmid.value == null || dmid.value === 0) return null;
    return { mkt: d.mkt, value: bpsFromPx(d.value, dmid.value), col: d.col };
}

export function getWaterfall(asset, fallback=WF_OTHER) {
    const a = String(asset ?? '').toUpperCase();
    return WATERFALL_BY_ASSET[a] ?? fallback;
}


function _getWaterfallLevel(ri, engine, side, qt, mktToSkip) {
    const asset = readCell(engine, ri, 'deskAsset') ?? readCell(engine, ri, 'bvalSubAssetClass');
    const assigned = readCell(engine, ri, 'assignedTrader');

    let waterfall = getWaterfall(assigned, null);
    if (!waterfall) waterfall = getWaterfall(asset);

    const skip = mktToSkip ? String(mktToSkip).toLowerCase() : null;
    for (let i = 0; i < waterfall.length; i++) {
        const a = waterfall[i];
        if (skip && a.toLowerCase() === skip) continue;
        const col = StringFormatter.clean_camel(a + '_' + side + '_' + qt);
        const v = readCell(engine, ri, col);
        if (v != null) return [a, v, col];
    }
    return null;
}

export function _normalizeQt(header) {
    if (!header) return 'default';
    header = String(header).toUpperCase();
    if (header.includes('PX')) return 'PX'
    if (header.includes('SPD')) return 'SPD'
    if (header.includes('MMY')
        || header.includes('YLD')
        || header.includes('YTC')
        || header.includes('YTW')
        || header.includes('YTM')
    ) return 'YLD'
    if (header.includes('CASH')
        || header.includes('PROCEEDS')
        || header.includes('DIRTY')
    ) return 'CASH'
    if (header.includes('DM')) return 'DM'
    if (header.includes('BPS'))  return "BPS"
    return null;
}

export function _inferSigFigs(engine, params, {field=null, value=null, active=true}={}) {
    const qtMap = engine.context?.page?.page$?.get('sigFigs');
    if (!qtMap) return undefined;

    if (field) {
        const headerQt = _normalizeQt(field);
        if (headerQt) return qtMap[headerQt] ?? undefined;
    }

    let qt;
    if (value) {
        qt = _normalizeQt(value);
        if (qt) return qtMap[qt] ?? undefined;
    }

    if (active) {
        qt = params?.data?.QT;
        if (qt == null) {
            const ri = params?.data?.__srcIndex ?? params?.data?.__pid
            if (ri != null) {
                qt = engine.getCell(ri, 'QT');
            }
        }
        if (qt) {
            qt = _normalizeQt(qt);
            return qtMap[qt] ?? qtMap['default'];
        }
    }

    return qtMap['default'];
}

