//  *   "+2" / "-1.5"         -> relative to default (active) market/side/qt
//  *   "BVAL +2"             -> relative w/ market override
//  *   "CBBT Ask +2"         -> relative w/ market + side override
//  *   "BVAL YLD +2"         -> relative w/ market + quote type override
//  *   "CBBT Ask PX +2"      -> relative w/ market + side + quote type override
//  *
//  * Assumes availability of:
//  *   _getNewLevelColumn(qt)                 -> e.g. 'newLevelPx'
//  *   getRefLevelCol({ market, side, qt })   -> e.g. 'bvalMidPx'
//  *   getRefLevelValue()                     -> (not used here but available)
//  *   getQuoteType()                         -> current grid QT (e.g. 'PX')
//  *   _getRelativeSkewDetails()              -> current { market, side, quoteType, value } (optional)
//  *   _normalizeQt(qt)                       -> canonical QT in ['PX','SPD','MMY','YLD','DM']
//  *
//  * Globals:
//  *   QUOTE_TYPES = ['PX','SPD','MMY','YLD','DM']
//  *   SIDES       = ['Bid','Mid','Ask']
//  */

const QT_ENUM = QUOTE_TYPES;
const SIDE_ENUM = SIDES;

// --- helpers --------------------------------------------------------------

const normalizeQt = (qtRaw) => {
    if (typeof _normalizeQt === 'function') return _normalizeQt(qtRaw);
    const up = String(qtRaw || '').toUpperCase();
    return QT_ENUM.includes(up) ? up : 'PX';
};

const qtPascal = (qt) => {
    // 'PX'->'Px', 'SPD'->'Spd', 'MMY'->'Mmy', 'YLD'->'Yld', 'DM'->'Dm'
    const up = String(qt || '').toUpperCase();
    if (up === 'PX')  return 'Px';
    if (up === 'SPD') return 'Spd';
    if (up === 'MMY') return 'Mmy';
    if (up === 'YLD') return 'Yld';
    if (up === 'DM')  return 'Dm';
    return null;
};

const parseRefColParts = (colId) => {
    // try to parse patterns like 'bvalMidPx', 'cbbtAskYld'
    const m = String(colId || '').match(/^([a-z]+)(Bid|Mid|Ask)(Px|Spd|Mmy|Yld|Dm)$/i);
    if (!m) return {};
    const market = m[1];
    const side   = m[2];
    const qtMap  = normalizeQt(m[3])
    return { market, side, qt };
};

const hasSignedNumber = (s) => /[-+]\d+(\.\d+)?$/.test(s.replace(/,/g, ''));
const onlyUnsignedNumber = (s) => /^\d+(\.\d+)?$/.test(s.replace(/,/g, ''));

function buildNewLevelUpdates(newLevelDisplayInput, ri, engine, settings) {

    // Current grid QT drives which newLevel* column we write.
    const newLevelCol = _getNewLevelColumn(engine, ri);
    if (nullish(newLevelDisplayInput)) {
        return [
            {column:newLevelCol, value:null, mode:'persist'},
            {column:"skewType", value:0, mode:'persist'},
            {column:"relativeSkewValue", value:null, mode:'persist'},
            {column:"relativeSkewTargetMkt", value:null, mode:'persist'},
            {column:"relativeSkewTargetQuoteType", value:null, mode:'persist'},
            {column:"relativeSkewTargetSide", value:null, mode:'persist'},
        ]
    }

    const raw = (newLevelDisplayInput ?? '').toString().trim();

    // Fixed (no sign, purely numeric) => skewType 0
    if (onlyUnsignedNumber(raw)) {
        const fixedVal = coerceToNumber(raw, {onNaN:null});
        return [
            //...clearOtherNewLevels(engine, ri, newLevelCol),
            {column:newLevelCol, value:fixedVal, mode:'persist'},
            {column:"skewType", value:0, mode:'persist'},
            {column:"relativeSkewValue", value:null, mode:'persist'},
            {column:"relativeSkewTargetMkt", value:null, mode:'persist'},
            {column:"relativeSkewTargetQuoteType", value:null, mode:'persist'},
            {column:"relativeSkewTargetSide", value:null, mode:'persist'},
        ]
    }

    // Otherwise treat as RELATIVE; must include an explicit +/-
    const cleaned = raw
    .replace(/[–—−]/g, '-')  // normalize unicode minus
     .replace(/[＋]/g, '+')
     .replace(/\s+/g, ' ')
     .trim();

    if (!hasSignedNumber(cleaned)) {
        const num = cleaned.match(/(\d+(?:\.\d+)?)/);
        if (num) {
            const fixedVal = coerceToNumber(num[1], {onNaN:null});
            return [
                {column:newLevelCol, value:fixedVal, mode:'persist'},
                {column:"skewType", value:0, mode:'persist'},
                {column:"relativeSkewValue", value:null, mode:'persist'},
                {column:"relativeSkewTargetMkt", value:null, mode:'persist'},
                {column:"relativeSkewTargetQuoteType", value:null, mode:'persist'},
                {column:"relativeSkewTargetSide", value:null, mode:'persist'},
            ]
        }
        throw new Error('Relative inputs must include + or - followed by a number (e.g., "+2").');
    }

    // Grab the LAST signed number in the string as the skew value.
    const numMatch = cleaned.match(/([+\-]\s*\d+(?:\.\d+)?)(?!.*[+\-]\s*\d)/);
    if (!numMatch) throw new Error('Could not parse relative skew value.');
    const skewVal = coerceToNumber(numMatch[1].replace(/\s+/g, ''), {onNaN:null});

    const head = cleaned.slice(0, numMatch.index).trim();
    const tokens = head ? head.split(/\s+/) : [];

    const currentRel = _getRelativeSkewDetails(engine, ri);
    const gridQt = getQuoteType(engine.getCell(ri, 'QT'));
    let relMarket = (settings.activeMarket || currentRel.market || '').toString().toUpperCase() || null;
    let relSide   = normalizeSide(settings.activeSide || (currentRel.side) || null, ri, engine);
    let relQt     = normalizeQt(settings.activeQuoteType || currentRel.quoteType || gridQt);
    let useWaterfall = true;

    for (const t of tokens) {
        if (!t) continue;

        const maybeSide = normalizeSide(t, ri, engine);
        if (maybeSide) {
            relSide = maybeSide;
            continue;
        }

        const up = t.toUpperCase();
        if (QT_ENUM.includes(up)) {
            relQt = normalizeQt(up);
            continue;
        }
        if (WF_FULL.includes(t.toLowerCase())) {
            relMarket = up;
            useWaterfall = false;
            continue;
        }
    }
    const refRaw   = getRefLevelRaw(ri, relMarket, relSide, relQt, engine, {waterfall:useWaterfall});
    const refCol = refRaw?.col;
    relMarket = refRaw?.mkt?.toUpperCase() ?? relMarket;
    const refVal = refCol ? engine.getCell(ri, refCol) : null;
    if (refVal == null) {
        engine.context.page.toastManager().error(`Missing reference data (${relMarket}) for bond, cannot apply this skew.`);
        return {
            [newLevelCol]: null,              // e.g. "[bvalMidPx] +2"
            skewType: 0,
            relativeSkewValue: null,    // numeric (preserve sign)
            relativeSkewTargetMkt: null, // e.g. "BVAL"
            relativeSkewTargetQuoteType: null,  // e.g. "PX"
            relativeSkewTargetSide: null,     // "Bid" | "Mid" | "Ask"
        };
    }


    const newValue     = refVal + skewVal;
    const display  = `${[relMarket, relSide, (relQt !== gridQt ? relQt : '')].filter(Boolean).join(' ')} ${skewVal >= 0 ? '+' : ''}${skewVal}`.trim();
    // console.log("FINALE:", display)

    return {
        [newLevelCol]: newValue,              // e.g. "[bvalMidPx] +2"
        skewType: 1,
        relativeSkewValue: skewVal,    // numeric (preserve sign)
        relativeSkewTargetMkt: relMarket, // e.g. "BVAL"
        relativeSkewTargetQuoteType: relQt,  // e.g. "PX"
        relativeSkewTargetSide: relSide,     // "Bid" | "Mid" | "Ask"
    };
}

