                const b_isin = engine.getCell(ri, 'bvalBenchmarkIsin');
                const a_isin = engine.getCell(ri, 'benchmarkIsin');

                let b_mid = settings?.UST_FULL?.has(b_isin) ? settings.UST_FULL.get(b_isin)?.midYld : null;
                let a_mid = settings?.UST_FULL?.has(a_isin) ? settings.UST_FULL.get(a_isin)?.midYld : null;

                b_mid = coerceToNumeric(b_mid, {onNaN: null});
                a_mid = coerceToNumeric(a_mid, {onNaN: null});

